import { type ReactElement } from 'react';

export const renderIconContent = (
  ctx: CanvasRenderingContext2D,
  icon: ReactElement,
  iconImages: Map<ReactElement, HTMLImageElement>,
  x: number,
  y: number,
) => {
  if (iconImages.has(icon)) {
    const imageElement = iconImages.get(icon);

    if (imageElement) {
      ctx.drawImage(imageElement, x, y);
    }
  }
};
